def find_anagram_groups(words):
    # Create a dictionary to hold our anagram groups. The key is the sorted word.
    groups = {}
    for word in words:
        key = ''.join(sorted(word))
        groups.setdefault(key, []).append(word)

    # Create a list of groups and sort them by size in descending order.
    sorted_groups = sorted(groups.values(), key=len, reverse=True)
    return sorted_groups

